import"./hoisted.b0ccece0.js";document.addEventListener("DOMContentLoaded",function(){const e=new Swiper(".swiper_banner_button",{slidesPerView:"auto",spaceBetween:32,loop:!0,autoplay:{delay:3e3,disableOnInteraction:!1},pagination:{el:".swiper-pagination",clickable:!0},breakpoints:{0:{slidesPerView:1,spaceBetween:10},640:{slidesPerView:"auto",spaceBetween:32}}});document.querySelectorAll(".swiper-slide video").forEach(t=>{t.addEventListener("play",()=>{e.autoplay.stop()}),t.addEventListener("pause",()=>{e.autoplay.start()}),t.addEventListener("ended",()=>{e.autoplay.start()})})});
